-- Data for Jobs
INSERT INTO "Jobs" ("Id", "Role", "Company", "LogoColor", "Location", "Mode", "Exp", "Comp", "Match", "Alumni", "AlumniInRole", "Description", "Responsibilities", "Skills", "Tags", "Team", "Posted") VALUES ('j1', 'Head of Product', 'Razorpay', '#2D6BE4', 'Bengaluru', 'Hybrid', '5–8 years', '₹52–68 LPA', 94, 12, 4, 'Own the entire product surface for Razorpay''s merchant-facing checkout and payments stack. Work with the CEO on 0→1 products that redefine how India pays.', '["Define and own the product roadmap for checkout and the merchant dashboard","Work with design and engineering to ship at high velocity","Manage a team of 6 PMs across checkout, risk, and analytics","Define pricing and packaging strategy alongside the CEO","Drive OKRs — GMV, activation rate, checkout success rate"]', '["Product Strategy","Payments Domain","Team Leadership","Data Analysis","Stakeholder Mgmt"]', '["Product","Fintech"]', 'Reports to CPO · team of 6 PMs + dedicated design pod', '2d ago');
INSERT INTO "Jobs" ("Id", "Role", "Company", "LogoColor", "Location", "Mode", "Exp", "Comp", "Match", "Alumni", "AlumniInRole", "Description", "Responsibilities", "Skills", "Tags", "Team", "Posted") VALUES ('j2', 'Staff Engineer – Infra', 'Flipkart', '#F7941D', 'Bengaluru', 'Hybrid', '5–8 years', '₹70–90 LPA', 88, 9, 2, 'Lead the platform infrastructure work underpinning Flipkart''s sale traffic — 100M+ concurrent users. Architect solutions for reliability, performance and cost.', '["Architect and lead distributed systems work across compute and storage","Drive reliability engineering — SLOs, error budgets, runbooks","Mentor 4–6 senior engineers; run hiring loops","Partner with product to make infra a competitive advantage","Own cost optimisation initiatives — ₹20Cr+ savings annually"]', '["Distributed Systems","Kubernetes","Go","System Design","SRE"]', '["Engineering","Infrastructure"]', 'Reports to VP Eng · works across Platform, Search and Supply-chain pods', '4d ago');
INSERT INTO "Jobs" ("Id", "Role", "Company", "LogoColor", "Location", "Mode", "Exp", "Comp", "Match", "Alumni", "AlumniInRole", "Description", "Responsibilities", "Skills", "Tags", "Team", "Posted") VALUES ('j3', 'VP – Strategy & Operations', 'Goldman Sachs', '#0A3B6B', 'Mumbai', 'On-site', '8+ years', '₹90 LPA–1.2 Cr', 81, 7, 1, 'Drive strategic initiatives across GS India''s technology and operations division. Partner with global leadership on market expansion and efficiency programs.', '["Own strategic planning cycle for India technology division (2000+ headcount)","Lead 3–5 cross-functional transformation programs simultaneously","Build board-level presentations and executive briefings","Drive vendor and partner relationships — $50M+ spend portfolio","Coach and develop a team of 8 analysts and associates"]', '["Strategy","Financial Modelling","Executive Communication","Program Management","Consulting"]', '["Strategy","Finance"]', 'Reports to MD Operations India · matrix to Global COO office', '1w ago');
INSERT INTO "Jobs" ("Id", "Role", "Company", "LogoColor", "Location", "Mode", "Exp", "Comp", "Match", "Alumni", "AlumniInRole", "Description", "Responsibilities", "Skills", "Tags", "Team", "Posted") VALUES ('j4', 'Engagement Manager', 'McKinsey', '#1C1C4E', 'Pan-India', 'Hybrid', '3–5 years', '₹48–60 LPA', 76, 21, 8, 'Lead client-facing project teams on strategy and digital transformation engagements. McKinsey India''s fastest-growing practice — tech, fintech and consumer sectors.', '["Lead day-to-day client delivery on 2–3 concurrent engagements","Manage teams of 3–5 consultants and business analysts","Build trusted advisor relationships with C-suite clients","Contribute to practice development and thought leadership","Drive proposals and account development"]', '["Problem Solving","Client Management","Team Leadership","PowerPoint","Financial Modelling"]', '["Strategy","Consulting"]', 'Reports to Associate Partner · McKinsey India Digital practice', '3d ago');
INSERT INTO "Jobs" ("Id", "Role", "Company", "LogoColor", "Location", "Mode", "Exp", "Comp", "Match", "Alumni", "AlumniInRole", "Description", "Responsibilities", "Skills", "Tags", "Team", "Posted") VALUES ('j5', 'Senior Product Manager', 'Zerodha', '#387ED1', 'Bengaluru', 'Remote', '3–5 years', '₹42–55 LPA', 72, 4, 2, 'Own the trader experience on Kite — India''s most-used trading platform. Work in a small high-trust team. No bureaucracy, full ownership.', '["Own and evolve the Kite web and mobile trading experience","Deeply understand retail trader mental models and workflows","Define and ship 0→1 features — options analytics, portfolio intelligence","Work directly with the founder on product direction","Drive data analysis on trading patterns and feature adoption"]', '["Product Management","Financial Markets","UX Thinking","SQL","Trader Domain"]', '["Product","Fintech"]', 'Small flat team — reports to Founder · 0 layers', '5d ago');
INSERT INTO "Jobs" ("Id", "Role", "Company", "LogoColor", "Location", "Mode", "Exp", "Comp", "Match", "Alumni", "AlumniInRole", "Description", "Responsibilities", "Skills", "Tags", "Team", "Posted") VALUES ('j6', 'Engineering Manager', 'Swiggy', '#FC8019', 'Bengaluru', 'Hybrid', '5–8 years', '₹65–85 LPA', 69, 6, 1, 'Lead Swiggy''s consumer app engineering team — 50M MAU. Drive the quarterly roadmap across Android, iOS and backend. Hire, grow, and retain top talent.', '["Manage a team of 12 engineers across Android, iOS and backend","Define team roadmap in partnership with product and design","Drive hiring — 4 open roles in your first quarter","Run engineering excellence initiatives — velocity, quality, oncall","Partner with Data Science on personalisation features"]', '["Engineering Management","Android/iOS","System Design","Hiring","Agile"]', '["Engineering","Consumer"]', 'Reports to Director of Engineering · Consumer Platform', '1w ago');
INSERT INTO "Jobs" ("Id", "Role", "Company", "LogoColor", "Location", "Mode", "Exp", "Comp", "Match", "Alumni", "AlumniInRole", "Description", "Responsibilities", "Skills", "Tags", "Team", "Posted") VALUES ('j7', 'Head of Growth', 'CRED', '#1A1A2E', 'Bengaluru', 'Hybrid', '5–8 years', '₹58–78 LPA', 65, 5, 1, 'Own CRED''s member growth and engagement funnel end-to-end. High-trust role with direct access to founders. Work at the intersection of product, data and brand.', '["Own member acquisition — paid, organic, referral channels","Define and run growth experiments at scale — 10M+ member base","Work with brand and creative on campaign strategy","Build and lead a team of 5 growth PMs and analysts","Drive cohort retention and engagement metrics"]', '["Growth Hacking","Performance Marketing","Product Analytics","A/B Testing","CRM"]', '["Product","Marketing"]', 'Reports to Co-founder · Growth pod', '6d ago');
INSERT INTO "Jobs" ("Id", "Role", "Company", "LogoColor", "Location", "Mode", "Exp", "Comp", "Match", "Alumni", "AlumniInRole", "Description", "Responsibilities", "Skills", "Tags", "Team", "Posted") VALUES ('j8', 'Product Lead – Commerce', 'Tata Digital', '#0032A0', 'Mumbai', 'On-site', '3–5 years', '₹44–58 LPA', 62, 3, 1, 'Define the next chapter for Tata Neu''s commerce experience — grocery, fashion, electronics. Work with India''s most iconic brand to build a super-app that matters.', '["Own product vision and roadmap for Tata Neu commerce verticals","Lead a team of 3 PMs and 1 UX researcher","Drive integration strategy across Tata group portfolio","Define success metrics and own the P&L impact","Work with tech leads to architect scalable commerce platform"]', '["Product Management","E-commerce","Retail Domain","Roadmap Planning","Stakeholder Mgmt"]', '["Product","E-commerce"]', 'Reports to VP Product · Tata Digital Mumbai HQ', '2w ago');

